import Foundation

/// A type with a direct, statically generated MessagePack representation.
///
/// Conformances are usually generated by the `@MessagePackSerializable`
/// macro, which serializes a struct as a map of field name to field value:
///
/// ```swift
/// @MessagePackSerializable
/// struct Foo {
///     let bar: Int
///     let hoge: String
/// }
///
/// let data = MessagePackSerializer.serialize(Foo(bar: 0, hoge: ""))
/// let foo = try MessagePackSerializer.deserialize(Foo.self, from: data)
/// ```
///
/// Unlike `Codable` with ``MessagePackEncoder``/``MessagePackDecoder``, this
/// path has no dynamic container machinery: the generated code writes and
/// reads the wire format directly, which makes it considerably faster. The
/// bytes produced are identical to what the `Codable` path produces for an
/// equivalent type.
///
/// Enums with a raw value don't need the macro: declaring the conformance is
/// enough, because a default implementation is provided for
/// `RawRepresentable` types whose `RawValue` conforms.
public protocol MessagePackSerializable {
    /// Writes the MessagePack representation of `self` to `writer`.
    func serialize(into writer: inout MessagePackWriter)

    /// Reads a value from `reader`, consuming exactly one MessagePack value.
    init(messagePack reader: inout MessagePackReader) throws(MessagePackError)
}

/// Generates a ``MessagePackSerializable`` conformance for a struct.
///
/// The struct is serialized as a MessagePack map with one entry per stored
/// property, keyed by property name, in declaration order. Deserialization
/// accepts fields in any order, skips unknown keys, throws
/// ``MessagePackError/missingField(_:)`` for absent non-optional fields
/// without a default value, and uses the property's default value (or `nil`
/// for optionals) when a field is absent.
///
/// - `@MessagePackKey("name")` overrides the map key for a property.
/// - `@MessagePackIgnored` excludes a stored property entirely; it must have
///   a default value (or be an optional `var`) so the generated initializer
///   compiles.
/// - Computed, `static`, and `lazy` properties are ignored. `let` properties
///   with a default value are serialized but not deserialized (they cannot
///   be assigned), matching `Codable` synthesis.
@attached(extension, conformances: MessagePackSerializable, names: named(serialize), named(init))
public macro MessagePackSerializable() =
    #externalMacro(module: "MessagePackSwiftMacros", type: "MessagePackSerializableMacro")

/// Excludes a stored property from `@MessagePackSerializable` serialization.
@attached(peer)
public macro MessagePackIgnored() =
    #externalMacro(module: "MessagePackSwiftMacros", type: "MessagePackIgnoredMacro")

/// Overrides the map key `@MessagePackSerializable` uses for a stored
/// property.
@attached(peer)
public macro MessagePackKey(_ key: StaticString) =
    #externalMacro(module: "MessagePackSwiftMacros", type: "MessagePackKeyMacro")

// MARK: - Serializer entry points

extension MessagePackSerializer {
    /// Serializes a ``MessagePackSerializable`` value into MessagePack binary
    /// data.
    ///
    /// Values whose lengths exceed the MessagePack limits (strings, binary,
    /// or containers beyond 2^32-1 bytes/elements), and dates outside the
    /// timestamp range, stop execution with a precondition failure.
    @inlinable
    public static func serialize<T: MessagePackSerializable>(_ value: T) -> Data {
        var writer = MessagePackWriter(initialCapacity: 1024)
        value.serialize(into: &writer)
        return writer.finish()
    }

    /// Deserializes MessagePack binary data into a ``MessagePackSerializable``
    /// value.
    ///
    /// Throws ``MessagePackError/trailingBytes`` if `data` contains bytes
    /// beyond the first top-level value.
    @inlinable
    public static func deserialize<T: MessagePackSerializable>(
        _ type: T.Type = T.self, from data: Data
    ) throws(MessagePackError) -> T {
        let result: Result<T, MessagePackError> = data.withUnsafeBytes { buffer in
            var reader = MessagePackReader(buffer: buffer)
            do throws(MessagePackError) {
                let value = try T(messagePack: &reader)
                guard reader.isAtEnd else {
                    throw MessagePackError.trailingBytes
                }
                return .success(value)
            } catch {
                return .failure(error)
            }
        }
        return try result.get()
    }
}

// MARK: - RawRepresentable default implementation

extension MessagePackSerializable where Self: RawRepresentable, RawValue: MessagePackSerializable {
    /// Serializes the raw value.
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) {
        rawValue.serialize(into: &writer)
    }

    /// Deserializes a raw value and converts it, throwing
    /// ``MessagePackError/invalidRawValue`` when no case matches.
    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        let rawValue = try RawValue(messagePack: &reader)
        guard let value = Self(rawValue: rawValue) else {
            throw MessagePackError.invalidRawValue
        }
        self = value
    }
}

// MARK: - Standard library conformances

extension Bool: MessagePackSerializable {
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) { writer.write(self) }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        self = try reader.readBool()
    }
}

