extension Optional: MessagePackSerializable where Wrapped: MessagePackSerializable {
    /// Serializes the wrapped value, or MessagePack nil for `nil`.
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) {
        if let value = self {
            value.serialize(into: &writer)
        } else {
            writer.writeNil()
        }
    }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        if reader.readNilIfPresent() {
            self = nil
        } else {
            self = .some(try Wrapped(messagePack: &reader))
        }
    }
}

extension Array: MessagePackSerializable where Element: MessagePackSerializable {
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) {
        writer.writeArrayHeader(count: count)
        for element in self {
            element.serialize(into: &writer)
        }
    }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        let count = try reader.readArrayHeader()
        self.init()
        reserveCapacity(count)
        for _ in 0..<count {
            append(try Element(messagePack: &reader))
        }
    }
}

extension Set: MessagePackSerializable where Element: MessagePackSerializable {
    /// Serialized as a MessagePack array. Element order is unspecified.
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) {
        writer.writeArrayHeader(count: count)
        for element in self {
            element.serialize(into: &writer)
        }
    }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        let count = try reader.readArrayHeader()
        self.init(minimumCapacity: count)
        for _ in 0..<count {
            insert(try Element(messagePack: &reader))
        }
    }
}

extension Dictionary: MessagePackSerializable
where Key: MessagePackSerializable, Value: MessagePackSerializable {
    /// Serialized as a MessagePack map. Entry order is unspecified.
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) {
        writer.writeMapHeader(count: count)
        for (key, value) in self {
            key.serialize(into: &writer)
            value.serialize(into: &writer)
        }
    }

    /// Duplicate keys on the wire are accepted; the last value wins.
    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        let count = try reader.readMapHeader()
        self.init(minimumCapacity: count)
        for _ in 0..<count {
            let key = try Key(messagePack: &reader)
            self[key] = try Value(messagePack: &reader)
        }
    }
}

// MARK: - Foundation and MessagePack type conformances

extension Data: MessagePackSerializable {
    /// Serialized as MessagePack binary (bin 8/16/32).
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) { writer.write(self) }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        self = try reader.readBinary()
    }
}

extension Date: MessagePackSerializable {
    /// Serialized as the timestamp extension type (-1), rounded to nanosecond
    /// precision. Dates outside the timestamp range (or with a non-finite
    /// interval) stop execution with a precondition failure; represent such
    /// values some other way before serializing.
    public func serialize(into writer: inout MessagePackWriter) {
        writer.write(MessagePackTimestamp(date: self))
    }

    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        self = try reader.readTimestamp().date
    }
}

extension MessagePackTimestamp: MessagePackSerializable {
    /// Serialized as the timestamp extension type (-1).
    @inlinable
    public func serialize(into writer: inout MessagePackWriter) { writer.write(self) }

    @inlinable
    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        self = try reader.readTimestamp()
    }
}

extension MessagePackValue: MessagePackSerializable {
    /// Serializes the value tree, allowing dynamically shaped fields inside
    /// `@MessagePackSerializable` types.
    public func serialize(into writer: inout MessagePackWriter) {
        writer.write(self)
    }

    public init(messagePack reader: inout MessagePackReader) throws(MessagePackError) {
        self = try reader.readValue()
    }
}
